private async getTokenFromLegacyWebAuthFlow(): Promise<string | null> {
  const manifest = chrome.runtime.getManifest();
  const clientId = manifest.oauth2?.client_id;
  const scopes = manifest.oauth2?.scopes?.join(' ');

  if (!clientId || !scopes) {
    console.error('[GoogleDriveSyncService] Missing oauth2 config');
    return null;
  }

  let redirectUrl = chrome.identity.getRedirectURL();
  // Some Chromium-based browsers (e.g., Arc) return custom scheme URIs
  // from getRedirectURL(), which Google rejects for 'WEB' client types.
  // Fall back to the standard chromiumapp.org URL.
  if (redirectUrl && !redirectUrl.startsWith('https://')) {
    const extensionId = chrome.runtime.id;
    if (extensionId) {
      redirectUrl = `https://${extensionId}.chromiumapp.org/`;
      console.warn(
        '[GoogleDriveSyncService] Corrected non-https redirect URL to:',
        redirectUrl,
      );
    }
  }
  console.log('[GoogleDriveSyncService] Auth flow starting with redirectUrl:', redirectUrl);

